  "E[X] = 0(1−p) + 1(p) = p.": "E[X] = 0(1−p) + 1(p) = p.",
  "E[X] = p for Bernoulli(p).": "E[X] = p pour Bernoulli(p).",
  "E[X] = Σ x P(X = x);  Var[X] = E[X²] − (E[X])²": "E[X] = Σ x P(X = x);  Var[X] = E[X²] − (E[X])²",
  "E_Na": "E_Na",
