  "ICA cleans multichannel recordings.": "ICA nettoie les enregistrements multicanaux.",
  "ICA differs from PCA mainly in that it seeks...": "L'ICA diffère de la PCA principalement en ce qu'elle cherche...",
  "ICA fails or becomes ambiguous when the sources are...": "L'ICA échoue ou devient ambigu lorsque les sources sont...",
  "ICA is widely used to clean and interpret multichannel neural recordings and imaging data.": "L’ICA est largement utilisé pour nettoyer et interpréter les enregistrements neuronaux multicanaux et les données d’imagerie.",
  "ICA seeks a linear unmixing of multivariate data into components that are as statistically independent as possible, not merely uncorrelated. Unlike PCA, it cares about higher-order statistics, which lets it recover non-Gaussian sources.": "L'ICA recherche un démixage linéaire de données multivariées en composants aussi statistiquement indépendants que possible, et non simplement non corrélés. Contrairement à la PCA, il se soucie des statistiques d'ordre supérieur, ce qui lui permet de récupérer des sources non gaussiennes.",
  "INSERT INTO APP_SETTINGS": "INSÉRER DANS APP_SETTINGS",
  "INSERT INTO LESSON_PROGRESS": "INSÉRER DANS LESSON_PROGRESS",
  "INSERT INTO QUIZ_ATTEMPTS": "INSÉRER DANS QUIZ_ATTEMPTS",
  "INSERT INTO REVIEW_STATE": "INSÉRER DANS LA REVIEW_STATE",
  "INSERT INTO STREAK_LOG": "INSÉRER DANS LE STREAK_LOG",
  "INSERT INTO app_settings (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value;": "INSERT INTO app_settings (clé, valeur) VALUES (?,?) ON CONFLICT(key) DO UPDATE SET value = exclus.value;",
  "INSERT INTO lesson_progress\n         (lesson_id, track_id, attempts, best_score, last_score, stars, mastery, last_attempt_at, completed_at)\n       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)\n       ON CONFLICT(lesson_id) DO UPDATE SET\n         track_id = excluded.track_id,\n         attempts = excluded.attempts,\n         best_score = excluded.best_score,\n         last_score = excluded.last_score,\n         stars = excluded.stars,\n         mastery = excluded.mastery,\n         last_attempt_at = excluded.last_attempt_at,\n         completed_at = COALESCE(lesson_progress.completed_at, excluded.completed_at);": "INSÉRER DANS lesson_progress\n         (lesson_id, track_id, tentatives, best_score, last_score, étoiles, maîtrise, last_attempt_at, completed_at)\n       VALEURS (?,?,?,?,?,?,?,?,?)\n       EN CONFLIT (lesson_id) FAIRE MISE À JOUR ENSEMBLE\n         track_id = exclu.track_id,\n         tentatives = exclu.tentatives,\n         best_score = exclu.best_score,\n         last_score = exclu.last_score,\n         stars = exclus.stars,\n         maîtrise = exclu.maîtrise,\n         last_attempt_at = exclu.last_attempt_at,\n         completed_at = COALESCE(lesson_progress.completed_at, exclu.completed_at);",
  "INSERT INTO quiz_attempts\n         (lesson_id, correct, total, score, xp_awarded, coins_awarded, attempted_at)\n       VALUES (?, ?, ?, ?, ?, ?, ?);": "INSÉRER DANS quiz_attempts\n         (lesson_id, correct, total, score, xp_awarded, coins_awarded, tentatived_at)\n       VALEURS (?,?,?,?,?,?,?);",
  "INSERT INTO review_state (lesson_id, last_reviewed_at, last_missed_at, priority)\n       VALUES (?, ?, ?, ?)\n       ON CONFLICT(lesson_id) DO UPDATE SET\n         last_reviewed_at = excluded.last_reviewed_at,\n         last_missed_at = excluded.last_missed_at,\n         priority = excluded.priority;": "INSÉRER DANS review_state (lesson_id, last_reviewed_at, last_missed_at, priorité)\n       VALEURS (?,?,?,?)\n       EN CONFLIT (lesson_id) FAIRE MISE À JOUR\n         last_reviewed_at = exclu.last_reviewed_at,\n         last_missed_at = exclu.last_missed_at,\n         priorité = exclu.priorité;",
  "INSERT INTO streak_log (day, lessons_completed, xp_earned) VALUES (?, ?, ?)\n       ON CONFLICT(day) DO UPDATE SET\n         lessons_completed = MAX(lessons_completed, excluded.lessons_completed),\n         xp_earned = MAX(xp_earned, excluded.xp_earned);": "INSÉRER DANS la séquencek_log (jour, leçons_completed, xp_earned) VALEURS (?,?,?)\n       EN CONFLIT (jour) FAIRE MISE À JOUR SET\n         leçons_completed = MAX(leçons_completed, exclu.leçons_completed),\n         xp_earned = MAX(xp_earned, exclu.xp_earned);",
  "INSERT INTO streak_log (day, lessons_completed, xp_earned) VALUES (?, ?, ?)\n       ON CONFLICT(day) DO UPDATE SET\n         lessons_completed = lessons_completed + excluded.lessons_completed,\n         xp_earned = xp_earned + excluded.xp_earned;": "INSÉRER DANS la séquencek_log (jour, leçons_completed, xp_earned) VALEURS (?,?,?)\n       EN CONFLIT (jour) FAIRE MISE À JOUR SET\n         leçons_completed = leçons_completed + exclu.leçons_completed,\n         xp_earned = xp_earned + exclu.xp_earned;",
