  "INSERT OR IGNORE INTO daily_quests (quest_id, day, progress, target, completed)\n         VALUES (?, ?, 0, ?, 0);": "INSÉRER OU IGNORER DANS daily_quests (quest_id, jour, progression, objectif, complété)\n         VALEURS (?,?, 0,?, 0);",
